  1→import React, { useState } from 'react';
  2→import { Settings, Bell, Mail, MessageSquare, Webhook, Lock } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { AlertType } from '../../types/v3-types';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  user: User | null;
  9→  onNavigate: (view: string) => void;
 10→}
 11→
 12→interface AlertConfig {
 13→  type: AlertType;
 14→  label: string;
 15→  description: string;
 16→  enabled: boolean;
 17→  inApp: boolean;
 18→  email: boolean;
 19→}
 20→
 21→const DEFAULT_CONFIGS: AlertConfig[] = [
 22→  { type: 'new_citation', label: 'Nouvelle citation détectée', description: 'Quand votre marque est nouvellement citée par un moteur IA', enabled: true, inApp: true, email: false },
 23→  { type: 'lost_citation', label: 'Citation perdue', description: 'Quand un moteur IA ne vous cite plus sur une requête', enabled: true, inApp: true, email: true },
 24→  { type: 'competitor_overtake', label: 'Dépassement par un concurrent', description: 'Quand un concurrent vous dépasse en visibilité IA', enabled: true, inApp: true, email: true },
 25→  { type: 'score_drop', label: 'Chute de score significative', description: 'Quand votre score AEO baisse de plus de 10 points', enabled: true, inApp: true, email: true },
 26→  { type: 'score_milestone', label: 'Objectif de score atteint', description: 'Quand votre score dépasse un seuil configuré', enabled: true, inApp: true, email: false },
 27→  { type: 'new_competitor_detected', label: 'Nouveau concurrent détecté', description: 'Quand un nouvel acteur apparaît dans les réponses IA', enabled: false, inApp: true, email: false },
 28→  { type: 'trending_query', label: 'Requête en tendance', description: 'Quand une requête génère un trafic inhabituel', enabled: false, inApp: true, email: false },
 29→  { type: 'weekly_digest', label: 'Résumé hebdomadaire', description: 'Récapitulatif de la semaine envoyé chaque lundi', enabled: true, inApp: false, email: true },
 30→  { type: 'monthly_report', label: 'Rapport mensuel', description: 'Rapport détaillé mensuel avec tendances et recommandations', enabled: true, inApp: true, email: true },
 31→];
 32→
 33→const AlertSettingsPage: React.FC<Props> = ({ onBack, user }) => {
 34→  const [configs, setConfigs] = useState<AlertConfig[]>(DEFAULT_CONFIGS);
 35→  const [scoreThreshold, setScoreThreshold] = useState(10);
 36→
 37→  const toggleEnabled = (type: AlertType) => {
 38→    setConfigs(prev => prev.map(c =>
 39→      c.type === type ? { ...c, enabled: !c.enabled } : c
 40→    ));
 41→  };
 42→
 43→  const toggleChannel = (type: AlertType, channel: 'inApp' | 'email') => {
 44→    setConfigs(prev => prev.map(c =>
 45→      c.type === type ? { ...c, [channel]: !c[channel] } : c
 46→    ));
 47→  };
 48→
 49→  return (
 50→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 pb-24">
 51→      <div className="mb-8">
 52→        <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
 53→          <div className="w-10 h-10 rounded-2xl bg-gray-500/20 flex items-center justify-center border border-gray-500/30">
 54→            <Settings size={24} className="text-gray-400" />
 55→          </div>
 56→          Paramètres d'alertes
 57→        </h1>
 58→        <p className="text-gray-500">Configurez quand et comment vous souhaitez être notifié.</p>
 59→      </div>
 60→
 61→      {/* Score threshold */}
 62→      <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] mb-8">
 63→        <h3 className="text-sm font-bold text-white mb-4">Seuil de chute de score</h3>
 64→        <div className="flex items-center gap-4">
 65→          <input
 66→            type="range"
 67→            min={5}
 68→            max={30}
 69→            value={scoreThreshold}
 70→            onChange={e => setScoreThreshold(Number(e.target.value))}
 71→            className="flex-1 accent-purple-500"
 72→          />
 73→          <span className="text-lg font-bold text-white w-16 text-center">{scoreThreshold} pts</span>
 74→        </div>
 75→        <p className="text-xs text-gray-500 mt-2">Alerter quand le score AEO baisse de plus de {scoreThreshold} points.</p>
 76→      </div>
 77→
 78→      {/* Alert types */}
 79→      <div className="space-y-3">
 80→        {configs.map(config => (
 81→          <div key={config.type} className={`ninja-card p-5 rounded-2xl border transition-all ${config.enabled ? 'border-white/[0.08]' : 'border-white/[0.04] opacity-50'}`}>
 82→            <div className="flex items-start justify-between gap-4">
 83→              <div className="flex-1 min-w-0">
 84→                <div className="flex items-center gap-2 mb-1">
 85→                  <h4 className="text-sm font-medium text-white">{config.label}</h4>
 86→                  <button
 87→                    onClick={() => toggleEnabled(config.type)}
 88→                    className={`relative w-10 h-5 rounded-full transition-colors ${config.enabled ? 'bg-purple-500' : 'bg-gray-700'}`}
 89→                  >
 90→                    <div className={`absolute top-0.5 w-4 h-4 rounded-full bg-white transition-transform ${config.enabled ? 'translate-x-5' : 'translate-x-0.5'}`} />
 91→                  </button>
 92→                </div>
 93→                <p className="text-xs text-gray-500">{config.description}</p>
 94→              </div>
 95→
 96→              {config.enabled && (
 97→                <div className="flex items-center gap-2 shrink-0">
 98→                  <button
 99→                    onClick={() => toggleChannel(config.type, 'inApp')}
100→                    className={`p-2 rounded-lg border transition-colors ${config.inApp ? 'bg-purple-500/20 border-purple-500/30 text-purple-400' : 'bg-white/[0.04] border-white/[0.06] text-gray-600'}`}
101→                    title="Notification in-app"
102→                  >
103→                    <Bell size={14} />
104→                  </button>
105→                  <button
106→                    onClick={() => toggleChannel(config.type, 'email')}
107→                    className={`p-2 rounded-lg border transition-colors ${config.email ? 'bg-purple-500/20 border-purple-500/30 text-purple-400' : 'bg-white/[0.04] border-white/[0.06] text-gray-600'}`}
108→                    title="Notification email"
109→                  >
110→                    <Mail size={14} />
111→                  </button>
112→                  <div className="p-2 rounded-lg bg-white/[0.02] border border-white/[0.04] text-gray-700 cursor-not-allowed" title="Slack — Coming soon">
113→                    <MessageSquare size={14} />
114→                  </div>
115→                  <div className="p-2 rounded-lg bg-white/[0.02] border border-white/[0.04] text-gray-700 cursor-not-allowed" title="Webhook — Coming soon">
116→                    <Webhook size={14} />
117→                  </div>
118→                </div>
119→              )}
120→            </div>
121→          </div>
122→        ))}
123→      </div>
124→
125→      {/* Coming soon channels */}
126→      <div className="ninja-card p-5 rounded-2xl border border-dashed border-white/[0.06] mt-6 flex items-center gap-4">
127→        <Lock size={18} className="text-gray-600 shrink-0" />
128→        <div>
129→          <p className="text-sm text-gray-400">Canaux avancés</p>
130→          <p className="text-xs text-gray-600">Slack et Webhook seront disponibles dans une future mise à jour.</p>
131→        </div>
132→      </div>
133→    </div>
134→  );
135→};
136→
137→export default AlertSettingsPage;
