  1→import React, { useState, useMemo, useCallback } from 'react';
  2→import { Bell, Check, CheckCheck, Trash2, Filter, AlertTriangle, Info, TrendingUp, Trophy, Target, Calendar, Settings } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { Alert, AlertType, AlertSeverity } from '../../types/v3-types';
  5→import { getAlerts, markAlertRead, markAllAlertsRead, deleteAlert } from '../../services/v3/citation-storage';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onNavigate: (view: string) => void;
 11→}
 12→
 13→const ALERT_TYPE_META: Record<AlertType, { icon: React.ElementType; label: string }> = {
 14→  new_citation: { icon: TrendingUp, label: 'Nouvelle citation' },
 15→  lost_citation: { icon: AlertTriangle, label: 'Citation perdue' },
 16→  competitor_overtake: { icon: Trophy, label: 'Dépassement concurrent' },
 17→  score_drop: { icon: AlertTriangle, label: 'Chute de score' },
 18→  score_milestone: { icon: TrendingUp, label: 'Objectif atteint' },
 19→  new_competitor_detected: { icon: Target, label: 'Nouveau concurrent' },
 20→  trending_query: { icon: Target, label: 'Requête tendance' },
 21→  weekly_digest: { icon: Calendar, label: 'Résumé hebdo' },
 22→  monthly_report: { icon: Calendar, label: 'Rapport mensuel' },
 23→  calibration_complete: { icon: Settings, label: 'Calibration terminée' },
 24→};
 25→
 26→const SEVERITY_STYLES: Record<AlertSeverity, { border: string; bg: string; text: string; dot: string }> = {
 27→  critical: { border: 'border-red-500/20', bg: 'bg-red-500/10', text: 'text-red-400', dot: 'bg-red-400' },
 28→  warning: { border: 'border-yellow-500/20', bg: 'bg-yellow-500/10', text: 'text-yellow-400', dot: 'bg-yellow-400' },
 29→  positive: { border: 'border-green-500/20', bg: 'bg-green-500/10', text: 'text-green-400', dot: 'bg-green-400' },
 30→  info: { border: 'border-blue-500/20', bg: 'bg-blue-500/10', text: 'text-blue-400', dot: 'bg-blue-400' },
 31→};
 32→
 33→const AlertsPage: React.FC<Props> = ({ onBack, user, onNavigate }) => {
 34→  const userId = user?.id || 'default';
 35→  const [alerts, setAlerts] = useState<Alert[]>(() => getAlerts(userId));
 36→  const [filterSeverity, setFilterSeverity] = useState<AlertSeverity | 'all'>('all');
 37→  const [filterRead, setFilterRead] = useState<'all' | 'unread' | 'read'>('all');
 38→
 39→  const filteredAlerts = useMemo(() => {
 40→    let result = [...alerts].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
 41→    if (filterSeverity !== 'all') result = result.filter(a => a.severity === filterSeverity);
 42→    if (filterRead === 'unread') result = result.filter(a => !a.readAt);
 43→    if (filterRead === 'read') result = result.filter(a => !!a.readAt);
 44→    return result;
 45→  }, [alerts, filterSeverity, filterRead]);
 46→
 47→  const unreadCount = useMemo(() => alerts.filter(a => !a.readAt).length, [alerts]);
 48→
 49→  const handleMarkRead = useCallback((alertId: string) => {
 50→    markAlertRead(userId, alertId);
 51→    setAlerts(getAlerts(userId));
 52→  }, [userId]);
 53→
 54→  const handleMarkAllRead = useCallback(() => {
 55→    markAllAlertsRead(userId);
 56→    setAlerts(getAlerts(userId));
 57→  }, [userId]);
 58→
 59→  const handleDelete = useCallback((alertId: string) => {
 60→    deleteAlert(userId, alertId);
 61→    setAlerts(getAlerts(userId));
 62→  }, [userId]);
 63→
 64→  return (
 65→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 pb-24">
 66→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
 67→        <div>
 68→          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
 69→            <div className="w-10 h-10 rounded-2xl bg-orange-500/20 flex items-center justify-center border border-orange-500/30 relative">
 70→              <Bell size={24} className="text-orange-400" />
 71→              {unreadCount > 0 && (
 72→                <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full text-[10px] text-white font-bold flex items-center justify-center">
 73→                  {unreadCount}
 74→                </span>
 75→              )}
 76→            </div>
 77→            Alertes
 78→          </h1>
 79→          <p className="text-gray-500">{alerts.length} alerte{alerts.length > 1 ? 's' : ''} &bull; {unreadCount} non lue{unreadCount > 1 ? 's' : ''}</p>
 80→        </div>
 81→        <div className="flex gap-3">
 82→          {unreadCount > 0 && (
 83→            <button onClick={handleMarkAllRead} className="px-4 py-2.5 bg-white/[0.06] border border-white/[0.1] text-white font-bold rounded-2xl hover:bg-white/[0.1] transition-colors text-sm flex items-center gap-2">
 84→              <CheckCheck size={16} /> Tout marquer comme lu
 85→            </button>
 86→          )}
 87→          <button onClick={() => onNavigate('alert-settings')} className="px-4 py-2.5 bg-white/[0.06] border border-white/[0.1] text-white font-bold rounded-2xl hover:bg-white/[0.1] transition-colors text-sm flex items-center gap-2">
 88→            <Settings size={16} /> Paramètres
 89→          </button>
 90→        </div>
 91→      </div>
 92→
 93→      {/* Filters */}
 94→      <div className="flex flex-wrap gap-3 mb-6">
 95→        <div className="flex gap-2">
 96→          {(['all', 'critical', 'warning', 'positive', 'info'] as const).map(sev => (
 97→            <button key={sev} onClick={() => setFilterSeverity(sev)} className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors border ${
 98→              filterSeverity === sev ? 'bg-orange-500/20 text-orange-300 border-orange-500/30' : 'bg-white/[0.04] text-gray-500 border-white/[0.06] hover:text-white'
 99→            }`}>
100→              {sev === 'all' ? 'Toutes' : sev === 'critical' ? 'Critiques' : sev === 'warning' ? 'Avertissements' : sev === 'positive' ? 'Positives' : 'Infos'}
101→            </button>
102→          ))}
103→        </div>
104→        <div className="flex gap-2">
105→          {(['all', 'unread', 'read'] as const).map(status => (
106→            <button key={status} onClick={() => setFilterRead(status)} className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors border ${
107→              filterRead === status ? 'bg-orange-500/20 text-orange-300 border-orange-500/30' : 'bg-white/[0.04] text-gray-500 border-white/[0.06] hover:text-white'
108→            }`}>
109→              {status === 'all' ? 'Toutes' : status === 'unread' ? 'Non lues' : 'Lues'}
110→            </button>
111→          ))}
112→        </div>
113→      </div>
114→
115→      {/* Alerts list */}
116→      <div className="space-y-3">
117→        {filteredAlerts.map(alert => {
118→          const typeMeta = ALERT_TYPE_META[alert.type];
119→          const sevStyle = SEVERITY_STYLES[alert.severity];
120→          const IconComp = typeMeta.icon;
121→
122→          return (
123→            <div key={alert.id} className={`ninja-card p-5 rounded-2xl border transition-all ${alert.readAt ? 'border-white/[0.04] opacity-60' : sevStyle.border}`}>
124→              <div className="flex items-start gap-4">
125→                <div className={`w-10 h-10 rounded-full ${sevStyle.bg} flex items-center justify-center ${sevStyle.text} shrink-0`}>
126→                  <IconComp size={18} />
127→                </div>
128→                <div className="flex-1 min-w-0">
129→                  <div className="flex items-center gap-2 mb-1">
130→                    {!alert.readAt && <span className={`w-2 h-2 rounded-full ${sevStyle.dot} shrink-0`} />}
131→                    <h4 className="text-sm font-medium text-white truncate">{alert.title}</h4>
132→                  </div>
133→                  <p className="text-xs text-gray-500 mb-2">{alert.message}</p>
134→                  <div className="flex items-center gap-3">
135→                    <span className={`text-[10px] font-medium px-2 py-0.5 rounded-full border ${sevStyle.bg} ${sevStyle.text}`}>
136→                      {typeMeta.label}
137→                    </span>
138→                    <span className="text-[10px] text-gray-600">{new Date(alert.createdAt).toLocaleDateString()}</span>
139→                  </div>
140→                </div>
141→                <div className="flex items-center gap-2 shrink-0">
142→                  {!alert.readAt && (
143→                    <button onClick={() => handleMarkRead(alert.id)} className="text-gray-600 hover:text-white transition-colors" title="Marquer comme lu">
144→                      <Check size={16} />
145→                    </button>
146→                  )}
147→                  <button onClick={() => handleDelete(alert.id)} className="text-gray-600 hover:text-red-400 transition-colors" title="Supprimer">
148→                    <Trash2 size={16} />
149→                  </button>
150→                </div>
151→              </div>
152→            </div>
153→          );
154→        })}
155→
156→        {filteredAlerts.length === 0 && (
157→          <div className="ninja-card p-12 rounded-2xl border border-dashed border-white/[0.08] text-center">
158→            <Bell size={32} className="text-gray-600 mx-auto mb-3" />
159→            <p className="text-sm text-gray-500">Aucune alerte pour le moment.</p>
160→            <p className="text-xs text-gray-600 mt-1">Les alertes apparaîtront ici quand des événements significatifs seront détectés.</p>
161→          </div>
162→        )}
163→      </div>
164→    </div>
165→  );
166→};
167→
168→export default AlertsPage;
