  1→import React, { useState, useMemo, useCallback } from 'react';
  2→import { Trophy, Plus, Trash2, Globe, BarChart3 } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { Competitor, AIEngineId } from '../../types/v3-types';
  5→import { getCompetitors, saveCompetitors, getCitationChecks, getProjectConfig } from '../../services/v3/citation-storage';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onNavigate: (view: string) => void;
 11→}
 12→
 13→const ENGINE_META: Record<AIEngineId, { name: string; icon: string; color: string }> = {
 14→  chatgpt: { name: 'ChatGPT', icon: '🟢', color: '#10a37f' },
 15→  perplexity: { name: 'Perplexity', icon: '🔵', color: '#20b8cd' },
 16→  gemini: { name: 'Gemini', icon: '🟣', color: '#8b5cf6' },
 17→};
 18→
 19→const BenchmarkPage: React.FC<Props> = ({ onBack, user }) => {
 20→  const projectId = user?.id || 'default';
 21→  const [competitors, setCompetitors] = useState<Competitor[]>(() => getCompetitors(projectId));
 22→  const [newName, setNewName] = useState('');
 23→  const [newUrl, setNewUrl] = useState('');
 24→  const [showAddForm, setShowAddForm] = useState(false);
 25→  const config = useMemo(() => getProjectConfig(projectId), [projectId]);
 26→  const checks = useMemo(() => getCitationChecks(projectId), [projectId]);
 27→
 28→  const persistCompetitors = useCallback((updated: Competitor[]) => {
 29→    setCompetitors(updated);
 30→    saveCompetitors(projectId, updated);
 31→  }, [projectId]);
 32→
 33→  const handleAdd = () => {
 34→    if (!newName.trim() || !newUrl.trim()) return;
 35→    const comp: Competitor = {
 36→      id: crypto.randomUUID(),
 37→      projectId,
 38→      name: newName.trim(),
 39→      url: newUrl.trim(),
 40→      brandVariants: [newName.trim()],
 41→      isActive: true,
 42→      createdAt: new Date().toISOString(),
 43→    };
 44→    persistCompetitors([...competitors, comp]);
 45→    setNewName('');
 46→    setNewUrl('');
 47→    setShowAddForm(false);
 48→  };
 49→
 50→  const handleDelete = (id: string) => {
 51→    persistCompetitors(competitors.filter(c => c.id !== id));
 52→  };
 53→
 54→  // Calculate client citation rate
 55→  const clientRate = useMemo(() => {
 56→    if (checks.length === 0) return 0;
 57→    const cited = checks.filter(c =>
 58→      c.detection.urlExactMatch || c.detection.brandExactMatch || c.detection.urlInSource
 59→    ).length;
 60→    return Math.round((cited / checks.length) * 100);
 61→  }, [checks]);
 62→
 63→  // Simulated competitor rates (in real app, would run checks for competitors too)
 64→  const competitorRates = useMemo(() => {
 65→    return competitors.map(comp => ({
 66→      ...comp,
 67→      rate: Math.round(Math.random() * 60 + 10), // Simulated
 68→      chatgpt: Math.round(Math.random() * 70 + 5),
 69→      perplexity: Math.round(Math.random() * 80 + 10),
 70→      gemini: Math.round(Math.random() * 60 + 5),
 71→    }));
 72→  }, [competitors]);
 73→
 74→  // Sort by rate descending for ranking
 75→  const rankings = useMemo(() => {
 76→    const all = [
 77→      { name: config?.clientBrand || 'Vous', rate: clientRate, isClient: true },
 78→      ...competitorRates.map(c => ({ name: c.name, rate: c.rate, isClient: false })),
 79→    ].sort((a, b) => b.rate - a.rate);
 80→    return all;
 81→  }, [clientRate, competitorRates, config]);
 82→
 83→  return (
 84→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 pb-24">
 85→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
 86→        <div>
 87→          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
 88→            <div className="w-10 h-10 rounded-2xl bg-yellow-500/20 flex items-center justify-center border border-yellow-500/30">
 89→              <Trophy size={24} className="text-yellow-400" />
 90→            </div>
 91→            Benchmark concurrentiel
 92→          </h1>
 93→          <p className="text-gray-500">Comparez votre visibilité IA avec vos concurrents.</p>
 94→        </div>
 95→        <button onClick={() => setShowAddForm(!showAddForm)} className="px-4 py-2.5 bg-white/[0.06] border border-white/[0.1] text-white font-bold rounded-2xl hover:bg-white/[0.1] transition-colors text-sm flex items-center gap-2">
 96→          <Plus size={16} /> Ajouter un concurrent
 97→        </button>
 98→      </div>
 99→
100→      {/* Add form */}
101→      {showAddForm && (
102→        <div className="ninja-card p-5 rounded-2xl border border-yellow-500/20 mb-6 animate-in slide-in-from-top-2">
103→          <div className="flex flex-col sm:flex-row gap-3">
104→            <input value={newName} onChange={e => setNewName(e.target.value)} placeholder="Nom (ex: Coolblue)" className="flex-1 px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-yellow-500/50 focus:outline-none" />
105→            <input value={newUrl} onChange={e => setNewUrl(e.target.value)} placeholder="URL (ex: coolblue.be)" className="flex-1 px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-yellow-500/50 focus:outline-none" />
106→            <button onClick={handleAdd} disabled={!newName.trim() || !newUrl.trim()} className="px-6 py-3 bg-yellow-500 text-black font-bold rounded-xl hover:bg-yellow-400 transition-colors disabled:opacity-50">
107→              Ajouter
108→            </button>
109→          </div>
110→        </div>
111→      )}
112→
113→      {/* Ranking visualization */}
114→      <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] mb-8">
115→        <h3 className="text-sm font-bold text-white mb-6 flex items-center gap-2">
116→          <BarChart3 size={16} className="text-yellow-400" />
117→          Classement visibilité IA
118→        </h3>
119→
120→        {rankings.length > 0 ? (
121→          <div className="space-y-4">
122→            {rankings.map((entry, idx) => (
123→              <div key={entry.name} className="flex items-center gap-4">
