106→                    <div className="bg-white/[0.03] p-3 rounded-xl">
107→                      <p className="text-[10px] text-gray-600 uppercase">Marque</p>
108→                      <p className="text-sm font-medium text-white">{check.detection.brandExactMatch ? '✅ Détectée' : '❌ Non'}</p>
109→                    </div>
110→                    <div className="bg-white/[0.03] p-3 rounded-xl">
111→                      <p className="text-[10px] text-gray-600 uppercase">Position</p>
112→                      <p className="text-sm font-medium text-white">
113→                        {check.detection.positionInResponse === 'first_paragraph' ? '🥇 Premier §' :
114→                         check.detection.positionInResponse === 'middle' ? '📍 Milieu' :
115→                         check.detection.positionInResponse === 'end' ? '📍 Fin' : '📎 Footnote'}
116→                      </p>
117→                    </div>
118→                    <div className="bg-white/[0.03] p-3 rounded-xl">
119→                      <p className="text-[10px] text-gray-600 uppercase">Sentiment</p>
120→                      <p className="text-sm font-medium text-white">
121→                        {check.detection.sentiment === 'positive' ? '👍 Positif' :
122→                         check.detection.sentiment === 'negative' ? '👎 Négatif' : '🔘 Neutre'}
123→                      </p>
124→                    </div>
125→                  </div>
126→
127→                  {/* Response text */}
128→                  <div className="bg-white/[0.02] p-4 rounded-xl border border-white/[0.06]">
129→                    <p className="text-[10px] text-gray-600 uppercase mb-2">Réponse du moteur</p>
130→                    <p className="text-xs text-gray-400 whitespace-pre-wrap max-h-[200px] overflow-y-auto custom-scrollbar">
131→                      {check.responseText}
132→                    </p>
133→                  </div>
134→
135→                  {/* Sources */}
136→                  {check.responseSources.length > 0 && (
137→                    <div className="mt-3">
138→                      <p className="text-[10px] text-gray-600 uppercase mb-1.5">Sources citées</p>
139→                      <div className="flex flex-wrap gap-2">
140→                        {check.responseSources.map((src, i) => (
141→                          <span key={i} className="text-[10px] px-2 py-1 bg-white/[0.04] border border-white/[0.06] rounded text-gray-500 flex items-center gap-1">
142→                            <ExternalLink size={10} /> {src}
143→                          </span>
144→                        ))}
145→                      </div>
146→                    </div>
147→                  )}
148→
149→                  {/* Competitors before */}
150→                  {check.detection.competitorsBeforeUs.length > 0 && (
151→                    <div className="mt-3">
152→                      <p className="text-[10px] text-red-400 uppercase mb-1.5">Concurrents cités avant vous</p>
153→                      <div className="flex flex-wrap gap-2">
154→                        {check.detection.competitorsBeforeUs.map((c, i) => (
155→                          <span key={i} className="text-[10px] px-2 py-1 bg-red-500/10 border border-red-500/20 rounded text-red-400">{c}</span>
156→                        ))}
157→                      </div>
158→                    </div>
159→                  )}
160→                </div>
161→              )}
162→            </div>
163→          );
164→        })}
165→
166→        {filteredChecks.length === 0 && (
167→          <div className="ninja-card p-12 rounded-2xl border border-dashed border-white/[0.08] text-center">
168→            <FileSearch size={32} className="text-gray-600 mx-auto mb-3" />
169→            <p className="text-sm text-gray-500">Aucune vérification trouvée.</p>
170→            <p className="text-xs text-gray-600 mt-1">Lancez une vérification depuis le dashboard citations.</p>
171→          </div>
172→        )}
173→      </div>
174→    </div>
175→  );
176→};
177→
178→export default CitationDetailPage;
