 25→  const [newQueryText, setNewQueryText] = useState('');
 26→  const [newQueryType, setNewQueryType] = useState<QueryType>('informational');
 27→  const [showAddForm, setShowAddForm] = useState(false);
 28→  const [filterType, setFilterType] = useState<QueryType | 'all'>('all');
 29→
 30→  // Setup form state
 31→  const config = useMemo(() => getProjectConfig(projectId), [projectId]);
 32→  const [setupNiche, setSetupNiche] = useState(config?.niche || '');
 33→  const [setupCountry, setSetupCountry] = useState(config?.country || 'Belgique');
 34→  const [setupBrand, setSetupBrand] = useState(config?.clientBrand || '');
 35→  const [setupUrl, setSetupUrl] = useState(config?.clientUrl || '');
 36→  const needsSetup = !config;
